var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"꽃 사세요, 꽃~","JPN":"花はいかがかね～","ENG":"Buy your bouquets and flowers!","TWN":"來買花喔～"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"아, 거기- 젊은 아가씨도 한 송이 받으시구랴.","JPN":"あっ、そこのお嬢ちゃんも一輪どうぞ。","ENG":"Young lady. Here. Have a flower.","TWN":"小姐～這束花送你。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"천리향이라… 화천에선 보기 드문 꽃이구려.","JPN":"瑞香か……華天では珍しい花ですね。","ENG":"Daphne... Not a common flower to see in Huatian.","TWN":"是月橘…這種花在華天很少見。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_NPC_CLAN_NULL","text":{"KOREA":"그래요. 전에는 이렇게 자주 피는 꽃이 아니었는데, 세상이 변해가고 있는 모양이지.","JPN":"そうじゃろ。もともとこんなによく咲く花じゃなかったのに、世の中が変わってきているようだね。","ENG":"Yes. It didn't bloom this frequently back then, but the world is changing.","TWN":"是啊，以前並不常看到這種花，看來世界正在發生變化。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"간만이오, 사저.","JPN":"ご無沙汰しております、師姉。","ENG":"Long time no see.","TWN":"師姐，好久不見。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"아, 사매구나.","JPN":"ああ、師妹か。","ENG":"Oh, you're here.","TWN":"喔，原來是師妹。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"같은 스승을 둔 제자끼리 이렇게 얼굴 마주보기도 쉽지 않네.","JPN":"同じ師匠の弟子同士でも、こうやって顔を合わせることが難しいとは。","ENG":"Why is it so hard to see each other when we have served the same master?","TWN":"我們雖然師出同門，但要見上一面也不容易呢。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"천리향은 흑동 문주의 죽음… 향을 피우러 오는 것이 도리이니 말이오.","JPN":"瑞香は黒東門主の喪失……お香を焚くために参るのが道理でございます。","ENG":"Daphne, the passing of Black East's sect leader... It is our duty to light an incense to pay our respects.","TWN":"月橘表示黑東掌門人的離世…理當來上香。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"여전히 쌀쌀맞은 반응이구나. 변함없이.","JPN":"相変わらず素っ気ないな。","ENG":"Cold, as usual, I see.","TWN":"你的反應都沒變呢，一樣冷淡。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"흑동의 사람은 사사로이 정을 두지 않소. 그것이 규칙이기에 따를 뿐.","JPN":"黒東の者は、私情を挟むことはありません。規則に従うだけです。","ENG":"Members of Black East care not about emotions. I am merely abiding by the rules.","TWN":"黑東的人不輕易表露情感，我只是遵守規則而已。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"사담은 이쯤 나누지. 장문인께서 너에게 물건을 남기셨어.","JPN":"雑談はここまでにしよう。掌門人が師妹にある物を残した。","ENG":"Enough small talk. The sect master has left you something.","TWN":"話家常就倒此為止，掌門人有東西要交給你。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이건…? 사부님의 무기구려.","JPN":"これは……？　師匠の武器ですか。","ENG":"This is... Master's weapon.","TWN":"這是…？師父的武器。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그래, 장문인께선 네가 흑동의 문주 자릴 이어받길 원하셨거든.","JPN":"そうだ、掌門人は師妹に黒東の門主を受け継いでもらいたかったのだ。","ENG":"Correct. The sect master wanted you to be the next sect leader.","TWN":"沒錯，掌門人希望由你來繼承黑東幫主的位置。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그러기 위해선, 전통에 따라 사매도 섭리음양의 시련을 치러야겠지.","JPN":"そのためには伝統に従い、師妹も燮理陰陽の試練を受けなければならないであろう。","ENG":"However, tradition dictates that you must first pass the trial of the balance of yin and yang.","TWN":"因此你也必須按照傳統，經過燮理陰陽的考試。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 창을 다룰 줄 모르오.","JPN":"自分は槍を扱えません。","ENG":"I do not know how to wield a spear.","TWN":"我不懂如何使用長槍。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"게다가 사부님의 자릴 이어받기 위한 전승 수업은 사저가 받지 않았소? ","JPN":"それに、師匠の跡を受け継ぐための伝承授業を受けているのも、自分ではありません。 ","ENG":"Also, was it not you who our master trained to be his successor?","TWN":"而且師姊不是一直有在接受訓練，預備要接師父的位置嗎？"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"뭐든 금방 배우는 게 네 체질이잖니. 문주의 역할이란 것도 차차 배워나가면 될 일이야.","JPN":"師妹は何でもすぐ覚えるでしょう？　門主の役割というものも、そのうち慣れていけばいいだけだ。","ENG":"Nonetheless, you are a quick study. You will learn how to assume the role of sect leader.","TWN":"你天生就學得快，一定也可以慢慢學會當幫主的。"},"stage":{"bg":"CLAN","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};